


































import _ from 'lodash';
import {
  Component,
  Prop,
  Vue,
} from 'vue-property-decorator';
import { CARD } from '@/interface/card';
import CardPopover from '@/components/CardPopover.vue';
import {
  saveStr,
  effectStr,
} from '@/utils/stringUtil';
import { countAll } from '@/utils/countUtil';
import {
  State,
  Action,
} from 'vuex-class';

@Component({
  components: {
  CardPopover
  }
  })
export default class MyCard
  extends Vue {
    @Prop() private title!: string;
    @Prop() private items!: Array < object > ;
    @State private myCard!: Array < any > ;
    @Action private deleteMyCard!: ({
      id,
      index,
    }: {
    id: string,
    index: number
    }) => void
    @Action private useMyCard!: ({
      id,
      index,
    }: {
    id: string,
    index: number
    }) => void
    @Action private counterIt!: (arr: any) => void
    private $alert!: any

    private effect(data: any) {
      const result = countAll(data);
      return effectStr(result);
    }

    private currentStr(value: any): string {
      return saveStr(value);
    }

    private deleteIt({
      id,
      index,
    }: {
    id: string,
    index: number
    }) {
      this.$alert('确定删除该组数据吗？', '提示', {
        confirmButtonText: '确定',
        callback: (action: string) => {
          if (action === 'confirm') {
            this.deleteMyCard({
              id,
              index,
            });
          }
        },
      });
    }

    private countIt({
      id,
      index,
    }: {
    id: string,
    index: number
    }) {
      this.$alert('使用该数据将覆盖当前计算器上的数据，确定计算吗？', '提示', {
        confirmButtonText: '确定',
        callback: (action: string) => {
          if (action === 'confirm') {
            if (!_.isEmpty(id)) {
              const newMyCard = _.filter(this.myCard, (v: any) => v.id === id);
              this.counterIt(newMyCard[0].data);
              return;
            }
            if (_.isNumber(index)) {
              this.counterIt(this.myCard[index].data);
            }
          }
        },
      });
    }

    private useIt({
      id,
      index,
    }: {
    id: string,
    index: number
    }) {
      this.$alert('使用该数据将覆盖当前模拟器上的数据，确定使用吗？', '提示', {
        confirmButtonText: '确定',
        callback: (action: string) => {
          if (action === 'confirm') {
            this.useMyCard({
              id,
              index,
            });
          }
        },
      });
    }

    private get chunkData() {
      const newList = [...this.myCard];
      const clapList = _.map(newList, (item: any) => {
        const {
          data = [],
        } = item;
        const clapData = data.reduce((a: any, b: any) => a.concat(b), []);
        return {
          ...item,
          data: clapData,
        };
      });
      return _.chunk(clapList, 4) || [];
    }
}
